import sqlite3
import os
import threading
from enum import IntEnum
from datetime import datetime
from typing import Optional


class AccessLevel(IntEnum):
    NONE = 0
    READ = 1
    WRITE = 2
    ADMIN = 3


class FileAccessControlSystem:
    """File access control system with database-backed permission checking."""

    def __init__(self, db_path: str = ":memory:"):
        self.db_path = db_path
        self._local = threading.local()
        self._init_db()

    def _get_connection(self) -> sqlite3.Connection:
        """Get a thread-local database connection."""
        if not hasattr(self._local, 'connection') or self._local.connection is None:
            self._local.connection = sqlite3.connect(self.db_path)
            self._local.connection.row_factory = sqlite3.Row
            self._local.connection.execute("PRAGMA journal_mode=WAL")
        return self._local.connection

    def _init_db(self):
        """Initialize the database schema."""
        conn = self._get_connection()
        cursor = conn.cursor()

        cursor.executescript("""
            CREATE TABLE IF NOT EXISTS users (
                user_id INTEGER PRIMARY KEY AUTOINCREMENT,
                username TEXT UNIQUE NOT NULL,
                is_active BOOLEAN DEFAULT 1,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            );

            CREATE TABLE IF NOT EXISTS files (
                file_id INTEGER PRIMARY KEY AUTOINCREMENT,
                file_path TEXT UNIQUE NOT NULL,
                description TEXT,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            );

            CREATE TABLE IF NOT EXISTS permissions (
                permission_id INTEGER PRIMARY KEY AUTOINCREMENT,
                user_id INTEGER NOT NULL,
                file_id INTEGER NOT NULL,
                access_level INTEGER NOT NULL DEFAULT 0,
                granted_by INTEGER,
                granted_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                expires_at TIMESTAMP,
                FOREIGN KEY (user_id) REFERENCES users(user_id),
                FOREIGN KEY (file_id) REFERENCES files(file_id),
                FOREIGN KEY (granted_by) REFERENCES users(user_id),
                UNIQUE(user_id, file_id)
            );

            CREATE TABLE IF NOT EXISTS access_log (
                log_id INTEGER PRIMARY KEY AUTOINCREMENT,
                user_id INTEGER NOT NULL,
                file_id INTEGER,
                file_path TEXT,
                action TEXT NOT NULL,
                success BOOLEAN NOT NULL,
                reason TEXT,
                timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                FOREIGN KEY (user_id) REFERENCES users(user_id),
                FOREIGN KEY (file_id) REFERENCES files(file_id)
            );

            CREATE INDEX IF NOT EXISTS idx_permissions_user_file 
                ON permissions(user_id, file_id);
            CREATE INDEX IF NOT EXISTS idx_access_log_timestamp 
                ON access_log(timestamp);
            CREATE INDEX IF NOT EXISTS idx_files_path 
                ON files(file_path);
        """)
        conn.commit()

    def add_user(self, username: str) -> int:
        """Add a new user to the system."""
        conn = self._get_connection()
        cursor = conn.cursor()
        try:
            cursor.execute(
                "INSERT INTO users (username) VALUES (?)",
                (username,)
            )
            conn.commit()
            return cursor.lastrowid
        except sqlite3.IntegrityError:
            raise ValueError(f"User '{username}' already exists")

    def deactivate_user(self, username: str):
        """Deactivate a user, effectively revoking all access."""
        conn = self._get_connection()
        cursor = conn.cursor()
        cursor.execute(
            "UPDATE users SET is_active = 0 WHERE username = ?",
            (username,)
        )
        conn.commit()
        if cursor.rowcount == 0:
            raise ValueError(f"User '{username}' not found")

    def register_file(self, file_path: str, description: str = "") -> int:
        """Register a file in the access control system."""
        conn = self._get_connection()
        cursor = conn.cursor()
        try:
            cursor.execute(
                "INSERT INTO files (file_path, description) VALUES (?, ?)",
                (file_path, description)
            )
            conn.commit()
            return cursor.lastrowid
        except sqlite3.IntegrityError:
            raise ValueError(f"File '{file_path}' is already registered")

    def grant_permission(
        self,
        username: str,
        file_path: str,
        access_level: AccessLevel,
        granted_by: Optional[str] = None,
        expires_at: Optional[datetime] = None
    ):
        """Grant or update a user's permission for a file."""
        conn = self._get_connection()
        cursor = conn.cursor()

        # Get user_id
        cursor.execute("SELECT user_id FROM users WHERE username = ?", (username,))
        user_row = cursor.fetchone()
        if not user_row:
            raise ValueError(f"User '{username}' not found")
        user_id = user_row['user_id']

        # Get file_id
        cursor.execute("SELECT file_id FROM files WHERE file_path = ?", (file_path,))
        file_row = cursor.fetchone()
        if not file_row:
            raise ValueError(f"File '{file_path}' is not registered")
        file_id = file_row['file_id']

        # Get granted_by user_id if provided
        granted_by_id = None
        if granted_by:
            cursor.execute("SELECT user_id FROM users WHERE username = ?", (granted_by,))
            granter_row = cursor.fetchone()
            if granter_row:
                granted_by_id = granter_row['user_id']

        expires_at_str = expires_at.isoformat() if expires_at else None

        cursor.execute("""
            INSERT INTO permissions (user_id, file_id, access_level, granted_by, expires_at)
            VALUES (?, ?, ?, ?, ?)
            ON CONFLICT(user_id, file_id) DO UPDATE SET
                access_level = excluded.access_level,
                granted_by = excluded.granted_by,
                granted_at = CURRENT_TIMESTAMP,
                expires_at = excluded.expires_at
        """, (user_id, file_id, int(access_level), granted_by_id, expires_at_str))
        conn.commit()

    def revoke_permission(self, username: str, file_path: str):
        """Revoke a user's permission for a file."""
        conn = self._get_connection()
        cursor = conn.cursor()

        cursor.execute("SELECT user_id FROM users WHERE username = ?", (username,))
        user_row = cursor.fetchone()
        if not user_row:
            raise ValueError(f"User '{username}' not found")

        cursor.execute("SELECT file_id FROM files WHERE file_path = ?", (file_path,))
        file_row = cursor.fetchone()
        if not file_row:
            raise ValueError(f"File '{file_path}' is not registered")

        cursor.execute(
            "DELETE FROM permissions WHERE user_id = ? AND file_id = ?",
            (user_row['user_id'], file_row['file_id'])
        )
        conn.commit()

    def _check_permission(
        self,
        username: str,
        file_path: str,
        required_level: AccessLevel
    ) -> tuple[bool, str]:
        """
        Check if a user has the required permission level for a file.
        Returns (has_permission, reason).
        Always queries the database fresh to handle frequent permission changes.
        """
        conn = self._get_connection()
        cursor = conn.cursor()

        # Check user exists and is active
        cursor.execute(
            "SELECT user_id, is_active FROM users WHERE username = ?",
            (username,)
        )
        user_row = cursor.fetchone()
        if not user_row:
            return False, "User not found"
        if not user_row['is_active']:
            return False, "User account is deactivated"

        user_id = user_row['user_id']

        # Check file is registered
        cursor.execute(
            "SELECT file_id FROM files WHERE file_path = ?",
            (file_path,)
        )
        file_row = cursor.fetchone()
        if not file_row:
            return False, "File is not registered in the system"

        file_id = file_row['file_id']

        # Check permission - fresh query every time for frequently changing permissions
        cursor.execute("""
            SELECT access_level, expires_at
            FROM permissions
            WHERE user_id = ? AND file_id = ?
        """, (user_id, file_id))

        perm_row = cursor.fetchone()
        if not perm_row:
            return False, "No permission granted for this file"

        # Check expiration
        if perm_row['expires_at']:
            expires_at = datetime.fromisoformat(perm_row['expires_at'])
            if datetime.now() > expires_at:
                # Clean up expired permission
                cursor.execute(
                    "DELETE FROM permissions WHERE user_id = ? AND file_id = ?",
                    (user_id, file_id)
                )
                conn.commit()
                return False, "Permission has expired"

        access_level = AccessLevel(perm_row['access_level'])
        if access_level >= required_level:
            return True, f"Access granted (level: {access_level.name})"
        else:
            return False, (
                f"Insufficient permission level. "
                f"Required: {required_level.name}, "
                f"Current: {access_level.name}"
            )

    def _log_access(
        self,
        username: str,
        file_path: str,
        action: str,
        success: bool,
        reason: str
    ):
        """Log an access attempt."""
        conn = self._get_connection()
        cursor = conn.cursor()

        cursor.execute("SELECT user_id FROM users WHERE username = ?", (username,))
        user_row = cursor.fetchone()
        user_id = user_row['user_id'] if user_row else None

        cursor.execute("SELECT file_id FROM files WHERE file_path = ?", (file_path,))
        file_row = cursor.fetchone()
        file_id = file_row['file_id'] if file_row else None

        cursor.execute("""
            INSERT INTO access_log (user_id, file_id, file_path, action, success, reason)
            VALUES (?, ?, ?, ?, ?, ?)
        """, (user_id, file_id, file_path, action, success, reason))
        conn.commit()

    def read_file(self, username: str, file_path: str) -> str:
        """
        Check if user has read permission, then open and return file contents.
        
        Args:
            username: The username requesting access
            file_path: Path to the file to read
            
        Returns:
            The contents of the file as a string
            
        Raises:
            PermissionError: If the user doesn't have read access
            FileNotFoundError: If the file doesn't exist on disk
            IOError: If there's an error reading the file
        """
        # Check permission (always fresh from database)
        has_permission, reason = self._check_permission(
            username, file_path, AccessLevel.READ
        )

        if not has_permission:
            self._log_access(username, file_path, "READ", False, reason)
            raise PermissionError(
                f"Access denied for user '{username}' on file '{file_path}': {reason}"
            )

        # Check file exists on disk
        if not os.path.exists(file_path):
            self._log_access(
                username, file_path, "READ", False, "File not found on disk"
            )
            raise FileNotFoundError(f"File not found: {file_path}")

        if not os.path.isfile(file_path):
            self._log_access(
                username, file_path, "READ", False, "Path is not a file"
            )
            raise IOError(f"Path is not a file: {file_path}")

        # Read and return file contents
        try:
            with open(file_path, 'r', encoding='utf-8') as f:
                contents = f.read()
            self._log_access(username, file_path, "READ", True, reason)
            return contents
        except UnicodeDecodeError:
            # Try binary read as fallback
            with open(file_path, 'rb') as f:
                contents = f.read()
            self._log_access(username, file_path, "READ_BINARY", True, reason)
            return contents.decode('utf-8', errors='replace')
        except Exception as e:
            self._log_access(
                username, file_path, "READ", False, f"IO Error: {str(e)}"
            )
            raise IOError(f"Error reading file '{file_path}': {str(e)}")

    def get_access_log(
        self,
        username: Optional[str] = None,
        file_path: Optional[str] = None,
        limit: int = 100
    ) -> list[dict]:
        """Retrieve access log entries with optional filtering."""
        conn = self._get_connection()
        cursor = conn.cursor()

        query = """
            SELECT al.log_id, u.username, al.file_path, al.action, 
                   al.success, al.reason, al.timestamp
            FROM access_log al
            LEFT JOIN users u ON al.user_id = u.user_id
            WHERE 1=1
        """
        params = []

        if username:
            query += " AND u.username = ?"
            params.append(username)
        if file_path:
            query += " AND al.file_path = ?"
            params.append(file_path)

        query += " ORDER BY al.timestamp DESC LIMIT ?"
        params.append(limit)

        cursor.execute(query, params)
        rows = cursor.fetchall()

        return [dict(row) for row in rows]

    def get_user_permissions(self, username: str) -> list[dict]:
        """Get all permissions for a user."""
        conn = self._get_connection()
        cursor = conn.cursor()

        cursor.execute("""
            SELECT f.file_path, p.access_level, p.granted_at, p.expires_at,
                   g.username as granted_by
            FROM permissions p
            JOIN users u ON p.user_id = u.user_id
            JOIN files f ON p.file_id = f.file_id
            LEFT JOIN users g ON p.granted_by = g.user_id
            WHERE u.username = ?
            ORDER BY f.file_path
        """, (username,))

        results = []
        for row in cursor.fetchall():
            results.append({
                'file_path': row['file_path'],
                'access_level': AccessLevel(row['access_level']).name,
                'granted_at': row['granted_at'],
                'expires_at': row['expires_at'],
                'granted_by': row['granted_by']
            })
        return results

    def close(self):
        """Close the database connection."""
        if hasattr(self._local, 'connection') and self._local.connection:
            self._local.connection.close()
            self._local.connection = None


